backoff := time.Millisecond * 10
maxBackoff := time.Second * 10
errorCount := 0

for {
    conn, err := listener.Accept()
    if err != nil {
        errorCount++
        // Apply exponential backoff
        time.Sleep(backoff)
        backoff *= 2
        if backoff > maxBackoff {
            backoff = maxBackoff
        }
        // Optionally break after too many errors
        if errorCount > 10 {
            logger.Error("too many errors, exiting")
